"use client";
import { useState } from "react";
import { motion, useReducedMotion } from "framer-motion";
const stages=[['Prepared','Materials are assembled.'],['Reviewed','A teammate checked the details.'],['Approved','The handoff is cleared.']];
export default function ApprovalTrailChip(){const [step,setStep]=useState(0);const reduced=useReducedMotion();const done=step===2;const advance=()=>setStep(done?0:step+1);return <section className="w-full max-w-sm rounded-[22px] border border-[#ececee] bg-white p-5 shadow-[0_10px_28px_rgba(17,17,17,.06)]"><p className="text-xs font-bold uppercase tracking-[.14em] text-[#4a4a4f]">approval trail</p><div className="relative mt-4 grid grid-cols-3 gap-1"><motion.i aria-hidden animate={{x:step*94}} transition={reduced?{duration:.12}:{type:'spring',stiffness:350,damping:28}} className="absolute -top-1 h-2 w-2 rounded-full bg-[#2563eb]"/>{stages.map((stage,index)=><div key={stage[0]} className="min-h-11 rounded-xl border border-[#ececee] px-2 py-2 text-center"><span className="block text-[10px] font-bold text-[#4a4a4f]">0{index+1}</span><span className="block text-xs font-bold text-[#111]">{stage[0]}</span></div>)}</div><p aria-live="polite" className="mt-4 text-sm text-[#4a4a4f]"><strong className="text-[#111]">{stages[step][0]}.</strong> {stages[step][1]}</p><motion.button type="button" onClick={advance} whileHover={reduced?undefined:{y:-2}} whileTap={reduced?undefined:{y:1}} className="mt-4 min-h-11 w-full rounded-xl bg-[#111] text-sm font-bold text-white outline-offset-3 focus-visible:outline focus-visible:outline-[3px] focus-visible:outline-[#111]">{done?'Restart trail':'Advance approval'}</motion.button></section>}
